 33→function getTypeDescription(type: string): string {
 34→  const descriptions: Record<string, string> = {
 35→    heading: 'Large title text (headingMDL)',
 36→    text: 'Configurable text with type/color/bold',
 37→    section_heading: 'Section subtitle (subtitleXXL)',
 38→    balance_display: 'Points balance with label and values',
 39→    points_input: 'Numeric input field for points/reais',
 40→    button: 'CTA button with text and optional icon',
 41→    link: 'Pressable text link',
 42→    alert: 'Info/warning/error alert box',
 43→    list_text_icon: 'List of items with icon + description',
 44→    separator: 'Horizontal line divider',
 45→    icon_text_row: 'Row with icon and text side-by-side',
 46→    nav_header: 'Navigation header with back button',
 47→    rich_text: 'Inline formatted text with bold/link/icon nodes',
 48→  };
 49→  return descriptions[type] ?? type;
 50→}
