 52→function getPropDetail(propName: string, propDef: PropDef): string {
 53→  if (propDef.enum) return `enum: ${propDef.enum.join(' | ')}`;
 54→  if (propDef.type === 'boolean') return 'boolean';
 55→  if (propDef.type === 'number') return 'number';
 56→  if (propDef.type === 'string') return 'string';
 57→  if (propDef.type === 'array') return 'array';
 58→  if (propDef.type === 'object') return 'object';
 59→  return '';
 60→}
