 62→function findJsonContext(doc: string, pos: number): {
 63→  path: string[];
 64→  inKey: boolean;
 65→  inValue: boolean;
 66→  currentKey: string | null;
 67→  parentType: string | null;
 68→} {
 69→  const before = doc.slice(0, pos);
 70→
 71→  const path: string[] = [];
 72→  const stack: { key: string | null; isArray: boolean }[] = [];
 73→  let currentKey: string | null = null;
 74→  let inString = false;
 75→  let stringChar = '';
 76→  let lastKey: string | null = null;
 77→
 78→  for (let i = 0; i < before.length; i++) {
 79→    const ch = before[i];
 80→
 81→    if (inString) {
 82→      if (ch === '\\') { i++; continue; }
 83→      if (ch === stringChar) inString = false;
 84→      continue;
 85→    }
 86→
 87→    if (ch === '"' || ch === "'") {
 88→      inString = true;
 89→      stringChar = ch;
 90→      continue;
 91→    }
 92→
 93→    if (ch === '{') {
 94→      stack.push({ key: lastKey, isArray: false });
 95→      lastKey = null;
 96→    } else if (ch === '[') {
 97→      stack.push({ key: lastKey, isArray: true });
 98→      lastKey = null;
 99→    } else if (ch === '}' || ch === ']') {
100→      stack.pop();
101→      lastKey = null;
102→    } else if (ch === ':') {
103→      currentKey = lastKey;
104→    } else if (ch === ',') {
105→      lastKey = null;
106→      currentKey = null;
107→    }
108→
109→    if (ch === '"' || ch === "'") {
110→      const end = before.indexOf(ch === '"' ? '"' : "'", i + 1);
111→      if (end > i) {
112→        lastKey = before.slice(i + 1, end);
113→        i = end;
114→      }
115→    }
116→  }
117→
118→  for (const frame of stack) {
119→    if (frame.key) path.push(frame.key);
120→  }
121→
122→  const lineStart = before.lastIndexOf('\n') + 1;
123→  const line = before.slice(lineStart);
124→  const colonInLine = line.lastIndexOf(':');
125→  const inValueContext = colonInLine >= 0;
126→  const inKeyContext = !inValueContext;
127→
128→  let parentType: string | null = null;
129→  const typeMatch = before.match(/"type"\s*:\s*"([^"]+)"/g);
130→  if (typeMatch) {
131→    const lastTypeMatch = typeMatch[typeMatch.length - 1];
132→    const typeVal = lastTypeMatch.match(/"type"\s*:\s*"([^"]+)"/);
133→    if (typeVal) parentType = typeVal[1];
134→  }
135→
136→  return {
137→    path,
138→    inKey: inKeyContext,
139→    inValue: inValueContext,
140→    currentKey: currentKey || lastKey,
141→    parentType,
142→  };
143→}
