145→function getComponentTypeAtCursor(doc: string, pos: number): string | null {
146→  const before = doc.slice(0, pos);
147→  let depth = 0;
148→
149→  for (let i = before.length - 1; i >= 0; i--) {
150→    if (before[i] === '}') depth++;
151→    if (before[i] === '{') {
152→      depth--;
153→      if (depth < 0) {
154→        const chunk = before.slice(Math.max(0, i - 200), i);
155→        const outerBrace = chunk.lastIndexOf('{');
156→        if (outerBrace >= 0) {
157→          const outerChunk = doc.slice(Math.max(0, i - 200 + outerBrace), i + 200);
158→          const typeMatch = outerChunk.match(/"type"\s*:\s*"([^"]+)"/);
159→          if (typeMatch && (knownTypes as readonly string[]).includes(typeMatch[1])) {
160→            return typeMatch[1];
161→          }
162→        }
163→        break;
164→      }
165→    }
166→  }
167→  return null;
168→}
