170→function sduiCompletionSource(context: CompletionContext): CompletionResult | null {
171→  const doc = context.state.doc.toString();
172→  const pos = context.pos;
173→
174→  const beforeChar = doc.slice(Math.max(0, pos - 50), pos);
175→
176→  const typeValueMatch = beforeChar.match(/"type"\s*:\s*"([^"]*)$/);
177→  if (typeValueMatch) {
178→    const prefix = typeValueMatch[1];
179→    const from = pos - prefix.length;
180→    const options: Completion[] = (knownTypes as readonly string[]).map(t => ({
181→      label: t,
182→      type: 'enum',
183→      detail: getTypeDescription(t),
184→      boost: t.startsWith(prefix) ? 2 : 0,
185→    }));
186→    return { from, options, filter: true };
187→  }
188→
189→  const spacingValueMatch = beforeChar.match(
190→    /"(?:mt|mb|ml|mr)"\s*:\s*"([^"]*)$/
191→  );
192→  if (spacingValueMatch) {
193→    const prefix = spacingValueMatch[1];
194→    const from = pos - prefix.length;
195→    const options: Completion[] = spacingValues.map(v => ({
196→      label: v,
197→      type: 'enum',
198→      detail: 'spacing token',
199→    }));
200→    return { from, options, filter: true };
201→  }
202→
203→  const alertTypeMatch = beforeChar.match(/"type"\s*:\s*"([^"]*)$/) === null
204→    && beforeChar.match(/"type"\s*:\s*"([^"]*)$/i) === null
205→    ? null
206→    : null;
207→  void alertTypeMatch;
208→
209→  const propValueMatch = beforeChar.match(/"(\w+)"\s*:\s*"([^"]*)$/);
210→  if (propValueMatch) {
211→    const propName = propValueMatch[1];
212→    const prefix = propValueMatch[2];
213→    const from = pos - prefix.length;
214→
215→    if (['mt', 'mb', 'ml', 'mr'].includes(propName)) {
216→      return {
217→        from,
218→        options: spacingValues.map(v => ({
219→          label: v,
220→          type: 'enum' as const,
221→          detail: 'spacing token',
222→        })),
223→        filter: true,
224→      };
225→    }
226→
227→    if (propName === 'align') {
228→      return {
229→        from,
230→        options: ['left', 'center', 'right'].map(v => ({
231→          label: v,
232→          type: 'enum' as const,
233→          detail: 'text alignment',
234→        })),
235→        filter: true,
236→      };
237→    }
238→
239→    if (propName === 'keyboardType') {
240→      return {
241→        from,
242→        options: ['numeric', 'default', 'email-address', 'phone-pad'].map(v => ({
243→          label: v,
244→          type: 'enum' as const,
245→          detail: 'keyboard type',
246→        })),
247→        filter: true,
248→      };
249→    }
250→  }
251→
252→  const insidePropsObject = isInsidePropsObject(doc, pos);
253→  if (insidePropsObject) {
254→    const componentType = getComponentTypeForPropsAt(doc, pos);
255→    if (componentType) {
256→      const schema = componentPropsSchemas[componentType] as PropSchema | undefined;
257→      if (schema?.properties) {
258→        const word = context.matchBefore(/[\w]*/) || { from: pos, to: pos, text: '' };
259→        const existingKeys = getExistingKeysInObject(doc, pos);
260→        const required = (schema.required as readonly string[] | undefined) ?? [];
261→
262→        const options: Completion[] = Object.entries(schema.properties)
263→          .filter(([key]) => !existingKeys.has(key))
264→          .map(([key, def]) => {
265→            const isRequired = required.includes(key);
266→            const detail = getPropDetail(key, def as PropDef);
267→            return {
268→              label: `"${key}"`,
269→              displayLabel: key,
270→              type: isRequired ? 'property' : 'variable',
271→              detail: `${detail}${isRequired ? ' (required)' : ''}`,
272→              boost: isRequired ? 10 : 0,
273→              apply: buildPropApply(key, def as PropDef),
274→            };
275→          });
276→
277→        if (options.length === 0) return null;
278→        return { from: word.from, options, filter: true };
279→      }
280→    }
281→  }
282→
283→  const insideComponentObject = isInsideComponentObject(doc, pos);
284→  if (insideComponentObject) {
285→    const word = context.matchBefore(/[\w]*/) || { from: pos, to: pos, text: '' };
286→    const existingKeys = getExistingKeysInObject(doc, pos);
287→
288→    const options: Completion[] = componentStructureKeys
289→      .filter(key => !existingKeys.has(key))
290→      .map(key => {
291→        const detail = key === 'type' ? 'component type (required)'
292→          : key === 'props' ? 'component properties (required)'
293→          : 'conditional visibility';
294→        return {
295→          label: `"${key}"`,
296→          displayLabel: key,
297→          type: 'property',
298→          detail,
299→          boost: key === 'type' ? 10 : key === 'props' ? 9 : 0,
300→          apply: key === 'type' ? '"type": ""'
301→            : key === 'props' ? '"props": {}'
302→            : '"visible": { "rule": {} }',
303→        };
304→      });
305→
306→    if (options.length === 0) return null;
307→    return { from: word.from, options, filter: true };
308→  }
309→
310→  const insideTopLevel = isInsideTopLevelObject(doc, pos);
311→  if (insideTopLevel) {
312→    const word = context.matchBefore(/[\w]*/) || { from: pos, to: pos, text: '' };
313→    const existingKeys = getExistingKeysInObject(doc, pos);
314→
315→    const options: Completion[] = screenTopLevelKeys
316→      .filter(key => !existingKeys.has(key))
317→      .map(key => ({
318→        label: `"${key}"`,
319→        displayLabel: key,
320→        type: 'property',
321→        detail: key === 'id' ? 'screen identifier (required)'
322→          : key === 'body' ? 'component list (required)'
323→          : key === 'context' ? 'interpolation data'
324→          : key === 'header' ? 'screen header component'
325→          : 'screen footer component',
326→        boost: key === 'id' ? 10 : key === 'body' ? 9 : 0,
327→        apply: key === 'id' ? '"id": ""'
328→          : key === 'body' ? '"body": []'
329→          : key === 'context' ? '"context": {}'
330→          : key === 'header' ? '"header": { "type": "", "props": {} }'
331→          : '"footer": { "type": "", "props": {} }',
332→      }));
333→
334→    if (options.length === 0) return null;
335→    return { from: word.from, options, filter: true };
336→  }
337→
338→  return null;
339→}
340→
341→function buildPropApply(key: string, def: PropDef): string {
342→  if (def.type === 'boolean') return `"${key}": false`;
343→  if (def.type === 'number') return `"${key}": 0`;
344→  if (def.type === 'array') return `"${key}": []`;
345→  if (def.type === 'object') return `"${key}": {}`;
346→  if (def.enum) return `"${key}": ""`;
347→  return `"${key}": ""`;
348→}
349→
350→function isInsidePropsObject(doc: string, pos: number): boolean {
351→  const before = doc.slice(0, pos);
352→  let depth = 0;
353→
354→  for (let i = before.length - 1; i >= 0; i--) {
355→    if (before[i] === '}') depth++;
356→    if (before[i] === '{') {
357→      depth--;
358→      if (depth < 0) {
359→        const preceding = before.slice(Math.max(0, i - 30), i).trim();
360→        return /["']props["']\s*:\s*$/.test(preceding);
361→      }
362→    }
363→  }
364→  return false;
365→}
366→
367→function getComponentTypeForPropsAt(doc: string, pos: number): string | null {
368→  const before = doc.slice(0, pos);
369→  let depth = 0;
370→
371→  for (let i = before.length - 1; i >= 0; i--) {
372→    if (before[i] === '}') depth++;
373→    if (before[i] === '{') {
374→      depth--;
375→      if (depth < 0) {
376→        const outerStart = before.lastIndexOf('{', i - 1);
377→        if (outerStart >= 0) {
378→          const outerChunk = doc.slice(outerStart, outerStart + 300);
379→          const typeMatch = outerChunk.match(/"type"\s*:\s*"([^"]+)"/);
380→          if (typeMatch && (knownTypes as readonly string[]).includes(typeMatch[1])) {
381→            return typeMatch[1];
382→          }
383→        }
384→        break;
385→      }
386→    }
387→  }
388→  return null;
389→}
390→
391→function isInsideComponentObject(doc: string, pos: number): boolean {
392→  const before = doc.slice(0, pos);
393→  let depth = 0;
394→
395→  for (let i = before.length - 1; i >= 0; i--) {
396→    if (before[i] === '}' || before[i] === ']') depth++;
397→    if (before[i] === '{' || before[i] === '[') {
398→      depth--;
399→      if (depth < 0) {
400→        if (before[i] === '[') {
401→          const preceding = before.slice(Math.max(0, i - 30), i).trim();
402→          return /["']body["']\s*:\s*$/.test(preceding);
403→        }
404→        const preceding = before.slice(Math.max(0, i - 30), i).trim();
405→        if (/,\s*$/.test(preceding) || /\[\s*$/.test(preceding)) {
406→          const bracketSearch = before.slice(0, i);
407→          const bracketPos = bracketSearch.lastIndexOf('[');
408→          if (bracketPos >= 0) {
409→            const beforeBracket = bracketSearch.slice(Math.max(0, bracketPos - 30), bracketPos).trim();
410→            return /["']body["']\s*:\s*$/.test(beforeBracket);
411→          }
412→        }
413→        return false;
414→      }
415→    }
416→  }
417→  return false;
418→}
419→
420→function isInsideTopLevelObject(doc: string, pos: number): boolean {
421→  const before = doc.slice(0, pos);
422→  let depth = 0;
423→
424→  for (let i = before.length - 1; i >= 0; i--) {
425→    if (before[i] === '}' || before[i] === ']') depth++;
426→    if (before[i] === '{' || before[i] === '[') {
427→      depth--;
428→      if (depth < 0) {
429→        if (before[i] === '{') {
430→          const preceding = before.slice(0, i).trim();
431→          return preceding.length === 0 || preceding === '';
432→        }
433→        return false;
434→      }
435→    }
436→  }
437→  return false;
438→}
439→
440→function getExistingKeysInObject(doc: string, pos: number): Set<string> {
441→  const keys = new Set<string>();
442→  const before = doc.slice(0, pos);
443→  let depth = 0;
444→  let objStart = -1;
445→
446→  for (let i = before.length - 1; i >= 0; i--) {
447→    if (before[i] === '}' || before[i] === ']') depth++;
448→    if (before[i] === '{' || before[i] === '[') {
449→      depth--;
450→      if (depth < 0) {
451→        objStart = i;
452→        break;
453→      }
454→    }
455→  }
456→
457→  if (objStart < 0) return keys;
458→
459→  let endBrace = doc.indexOf('}', pos);
460→  if (endBrace < 0) endBrace = doc.length;
461→  const objectContent = doc.slice(objStart, endBrace + 1);
462→
463→  let keyMatch: RegExpExecArray | null;
464→  const keyRegex = /"([^"]+)"\s*:/g;
465→  while ((keyMatch = keyRegex.exec(objectContent)) !== null) {
466→    keys.add(keyMatch[1]);
467→  }
468→
469→  return keys;
470→}
