  return { from, options, filter: true };
}
```

**Problem**: The regex `/"type"\s*:\s*"([^"]*)$/` can match inside a string literal. If the user types `"description": "This is a type: "`, the autocomplete will trigger incorrectly.

**Impact**: Autocomplete popup appears in wrong contexts, confusing users and potentially corrupting valid JSON strings.

**Fix**: Verify cursor is not inside a string value before matching:

```typescript
function isInStringValue(doc: string, pos: number): boolean {
  let inString = false;
  let stringChar = '';

  for (let i = 0; i < pos; i++) {
    if (doc[i] === '\\') { i++; continue; }
    if (!inString && (doc[i] === '"' || doc[i] === "'")) {
      inString = true;
      stringChar = doc[i];
    } else if (inString && doc[i] === stringChar) {
      inString = false;
    }
  }

  return inString;
}

// Then in sduiCompletionSource:
if (isInStringValue(doc, pos)) return null;

const typeValueMatch = beforeChar.match(/"type"\s*:\s*"([^"]*)$/);
```

---

### 3. **Brace Depth Can Go Negative Without Recovery (lines 354-363)**

**File**: `sduiAutocomplete.ts:354-363`

```typescript
for (let i = before.length - 1; i >= 0; i--) {
  if (before[i] === '}') depth++;
  if (before[i] === '{') {
    depth--;
    if (depth < 0) {
      const preceding = before.slice(Math.max(0, i - 30), i).trim();
      return /["']props["']\s*:\s*$/.test(preceding);
