### 6. **activateOnTyping Without Explicit Check Guards**

**File**: `sduiAutocomplete.ts:472-479` + `CodeMirrorEditor.tsx:350`

```typescript
export function sduiAutocompletion() {
  return autocompletion({
    override: [sduiCompletionSource],
    activateOnTyping: true,
    maxRenderedOptions: 25,
    icons: true,
  });
}
```

**Problem**: With `activateOnTyping: true`, the completion source fires on **every single keystroke** without checking `context.explicit`. According to [CodeMirror autocomplete best practices](https://codemirror.net/examples/autocompletion/), completion sources should return `null` for implicit triggers when no relevant completion exists to avoid popup spam.

**Impact**: Users will see autocomplete popups when typing structural JSON characters (`,`, `:`, `{`, `}`), degrading UX significantly. This is the most common complaint in production JSON editors.

**Fix**: Add explicit checks throughout `sduiCompletionSource`:

```typescript
function sduiCompletionSource(context: CompletionContext): CompletionResult | null {
  const doc = context.state.doc.toString();
  const pos = context.pos;

  // Don't auto-trigger on structural characters unless explicitly requested
  if (!context.explicit) {
    const charBefore = doc[pos - 1];
    if (charBefore && /[{}[\]:,]/.test(charBefore)) {
      return null;
    }
  }

  // ... rest of implementation
}
```

